  1822→    private func schedulePostMagnifyCentering(for phase: NSEvent.Phase) {
  1823→        postMagnifyCenteringTask?.cancel()
  1824→        let shouldFinalize = phase.contains(.ended) || phase.contains(.cancelled)
  1825→        guard shouldFinalize else {
