  1827→            return
  1828→        }
  1829→        let phaseText = debugPhase(phase)
  1830→        let task = DispatchWorkItem { [weak self] in
  1831→            guard let self else { return }
  1832→            DebugCentering.log("magnify deferred finalize phase=\(phaseText)")
  1833→            // 只做 insets 更新 + clamp，不做 centerScrollPositionInValidRange()
  1834→            // 以保留用戶的 pan 位置
  1835→            self.applyCenteringInsetsIfNeeded(reason: "magnify.deferred.phase=\(phaseText)")
  1836→            self.isZooming = false
  1837→        }
  1838→        postMagnifyCenteringTask = task
  1839→        // 讓 AppKit magnify 事件鏈先落地，再做一次保底 clamp。
  1840→        DispatchQueue.main.async(execute: task)
  1841→    }
