  1886→    private func handleDrop(urls: [URL]) {
  1887→        guard let url = urls.first else { return }  // Use first item
  1888→
  1889→        // Folders always open fresh (no same-folder optimization)
  1890→        if URLFilter.isDirectory(url) {
  1891→            loadFolderAndSetTitle(imageFolderFromDrop(url: url))
  1892→            return
  1893→        }
  1894→
  1895→        // File: check for same-folder optimization
  1896→        let targetFolderURL = url.deletingLastPathComponent()
  1897→        if let currentFolder = folder, currentFolder.folderURL == targetFolderURL {
  1898→            // Same folder: try to navigate without reloading
  1899→            if let index = currentFolder.images.firstIndex(where: { $0.url == url }) {
  1900→                currentFolder.currentIndex = index
  1901→                // Sync spread index and reload current image (no folder scan needed)
  1902→                if settings.dualPageEnabled {
  1903→                    currentFolder.syncSpreadIndex()
  1904→                }
  1905→                loadCurrentImage(initialScroll: .top)
  1906→                updateWindowTitle()
  1907→                // Refresh grid if visible (same-folder doesn't go through loadFolder)
  1908→                if let grid = quickGridView {
  1909→                    grid.configure(items: currentFolder.images, currentIndex: index, loader: loader)
  1910→                }
  1911→                return  // Only return on successful optimization
  1912→            }
  1913→            // If not found, fall through to reload folder (new file case)
  1914→        }
  1915→
  1916→        // Different folder or new file in same folder: create new folder and load
  1917→        loadFolderAndSetTitle(imageFolderFromDrop(url: url))
