  1933→    private func optionScrollNavigate(forward: Bool, amount: Int) -> Bool {
  1934→        guard let folder, !folder.images.isEmpty else { return false }
  1935→        let direction: PrefetchDirection = forward ? .forward : .backward
  1936→        lastPrefetchDirection = direction
  1937→        var moved = false
  1938→        for _ in 0..<amount {
  1939→            if settings.dualPageEnabled {
  1940→                if forward {
