  1942→                } else {
  1943→                    if folder.goPreviousSpread() { moved = true }
  1944→                }
  1945→            } else {
  1946→                if forward {
  1947→                    if folder.goNext(amount: 1) { moved = true }
  1948→                } else {
  1949→                    if folder.goPrevious(amount: 1) { moved = true }
  1950→                }
  1951→            }
